import sys

n = Integer()

def coron(pol, X, Y, k=2):
    if pol.nvariables() != 2:
        raise ValueError("pol is not bivariate")

    P.<x,y> = PolynomialRing(ZZ)
    pol = pol(x,y)
    xoffset = 0
    while pol(xoffset,0) == 0:
        xoffset += 1
    pol = pol(x + xoffset, y)

    while gcd(pol(0,0), X) != 1:
        X = next_prime(X, proof=False)
    while gcd(pol(0,0), Y) != 1:
        Y = next_prime(Y, proof=False)

    pol = P(pol / gcd(pol.coefficients()))
    p00 = pol(0,0)
    delta = max(pol.degree(x), pol.degree(y))
    W = max(abs(i) for i in pol(x * X, y * Y).coefficients())
    u = W + ((1 - W) % abs(p00))
    N = u * (X * Y)^k
    p00inv = inverse_mod(p00, N)
    polq = P(sum((i * p00inv % N) * j for i, j in zip(pol.coefficients(), pol.monomials())))

    x, y = P.gens()
    polynomials = []
    for i in range(delta + k + 1):
        for j in range(delta + k + 1):
            if 0 <= i <= k and 0 <= j <= k:
                polynomials.append(polq * x^i * y^j * X^(k - i) * Y^(k - j))
            else:
                polynomials.append(x^i * y^j * N)

    monomials = []
    for poly in polynomials:
        for mono in poly.monomials():
            if mono not in monomials:
                monomials.append(mono)
    monomials.sort()

    L = matrix(ZZ, len(monomials))
    for i in range(len(monomials)):
        for j in range(len(monomials)):
            L[i, j] = polynomials[i](X * x, Y * y).monomial_coefficient(monomials[j])
    L = matrix(ZZ, sorted(L, reverse=True)).LLL()

    roots = []
    for i in range(L.nrows()):
        pol2 = P(sum(coeff * mono for coeff, mono in zip(L[i], monomials))(x / X, y / Y))
        r = pol.resultant(pol2, y)
        if r.is_constant():
            continue
        for x0, _ in r.univariate_polynomial().roots():
            for y0, _ in pol(x0, y).univariate_polynomial().roots():
                if pol(x0, y0) == 0:
                    roots.append((Integer(x0 - xoffset), Integer(y0)))
    return roots

print("n bits =", n.nbits())
sys.stdout.flush()
P.<x,y> = PolynomialRing(ZZ)
f = x * y * (x^2 + x + 1) - n

for pbits, rbits in [(752, 816), (768, 768), (784, 720)]:
    print("[*] trying pbits =", pbits, "rbits =", rbits, "k = 4")
    sys.stdout.flush()
    try:
        roots = coron(f, 2^pbits, 2^rbits, k=4)
    except Exception as ex:
        print("error:", ex)
        sys.stdout.flush()
        continue
    print("roots =", roots)
    sys.stdout.flush()
    for p, r in roots:
        q = p^2 + p + 1
        if p > 0 and r > 0 and n == p * q * r:
            print("FOUND", p.nbits(), q.nbits(), r.nbits())
            sys.stdout.flush()
            raise SystemExit

print("NO_ROOT")

